import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonNull_whenIsJsonNullTrue_returnsThisAsJsonNull() {
    JsonElement jsonElement = mock(JsonElement.class);
    when(jsonElement.isJsonNull()).thenReturn(true);
    // Cast jsonElement to JsonNull to simulate the expected return type
    JsonNull jsonNull = mock(JsonNull.class);
    // Use spy to override cast behavior by making jsonElement the same instance as jsonNull
    // But since we cannot cast mock directly, we mock jsonElement and stub getAsJsonNull to call real method.
    // Instead, use a subclass for this test to simulate behavior.
    JsonElement jsonElementSpy = new JsonNull() {
      @Override
      public boolean isJsonNull() {
        return true;
      }
    };
    JsonNull result = jsonElementSpy.getAsJsonNull();
    assertNotNull(result);
    assertSame(jsonElementSpy, result);
  }

  @Test
  void getAsJsonNull_whenIsJsonNullFalse_throwsIllegalStateException() {
    JsonElement jsonElement = new JsonElement() {
      @Override
      public boolean isJsonNull() {
        return false;
      }
      @Override
      public JsonElement deepCopy() {
        return null;
      }
    };
    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonNull);
    assertTrue(exception.getMessage().startsWith("Not a JSON Null: "));
    assertTrue(exception.getMessage().contains(jsonElement.toString()));
  }
}
